diff --git a/llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp b/llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp
index 9bd848552615..60331b60acc1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp
@@ -130,9 +130,17 @@ std::array<Value *, 2> Negator::getSortedOperandsOfBinOp(Instruction *I) {

   Value *X;

-  // -(-(X)) -> X.
-  if (match(V, m_Neg(m_Value(X))))
-    return X;
+  // -(-(X)) -> X, but only if the inner negation cannot produce poison
+  // due to nowrap flags. If the inner negate has NSW/NUW, then -(V) would be
+  // poison for some inputs, while X would not, so we cannot fold.
+  if (auto *BO = dyn_cast<BinaryOperator>(V)) {
+    if (BO->getOpcode() == Instruction::Sub &&
+        match(BO->getOperand(0), m_ZeroInt()) &&
+        match(BO->getOperand(1), m_Value(X))) {
+      if (!BO->hasNoSignedWrap() && !BO->hasNoUnsignedWrap())
+        return X;
+    }
+  }

   // Integral constants can be freely negated.
   if (match(V, m_AnyIntegralConstant()))
@@ -326,15 +334,46 @@ std::array<Value *, 2> Negator::getSortedOperandsOfBinOp(Instruction *I) {
   case Instruction::Select: {
     if (isKnownNegation(I->getOperand(1), I->getOperand(2), /*NeedNSW=*/false,
                         /*AllowPoison=*/false)) {
-      // Of one hand of select is known to be negation of another hand,
-      // just swap the hands around.
-      auto *NewSelect = cast<SelectInst>(I->clone());
-      // Just swap the operands of the select.
-      NewSelect->swapValues();
-      // Don't swap prof metadata, we didn't change the branch behavior.
-      NewSelect->setName(I->getName() + ".neg");
-      Builder.Insert(NewSelect);
-      return NewSelect;
+      // If one hand of select is known to be the negation of the other hand,
+      // then -select(c, A, B) == select(c, B, A). However, nowrap flags on the
+      // hands (e.g. sub nsw 0, X) may introduce poison when selecting those
+      // values directly. To avoid this, rebuild any overflowing binops used as
+      // hands without nowrap flags before swapping them.
+      auto getSafeNoWrapCopy = [&](Value *Op) -> Value * {
+        if (auto *OBO = dyn_cast<OverflowingBinaryOperator>(Op)) {
+          // Only rebuild if there actually are nowrap flags to drop.
+          if (!OBO->hasNoSignedWrap() && !OBO->hasNoUnsignedWrap())
+            return Op;
+          Instruction *BO = cast<Instruction>(Op);
+          switch (BO->getOpcode()) {
+          case Instruction::Add:
+            return Builder.CreateAdd(BO->getOperand(0), BO->getOperand(1),
+                                     BO->getName() + ".nwrap", /*HasNUW*/false,
+                                     /*HasNSW*/false);
+          case Instruction::Sub:
+            return Builder.CreateSub(BO->getOperand(0), BO->getOperand(1),
+                                     BO->getName() + ".nwrap", /*HasNUW*/false,
+                                     /*HasNSW*/false);
+          case Instruction::Mul:
+            return Builder.CreateMul(BO->getOperand(0), BO->getOperand(1),
+                                     BO->getName() + ".nwrap", /*HasNUW*/false,
+                                     /*HasNSW*/false);
+          case Instruction::Shl:
+            return Builder.CreateShl(BO->getOperand(0), BO->getOperand(1),
+                                     BO->getName() + ".nwrap", /*HasNUW*/false,
+                                     /*HasNSW*/false);
+          default:
+            return Op;
+          }
+        }
+        return Op;
+      };
+
+      Value *SafeOp1 = getSafeNoWrapCopy(I->getOperand(1));
+      Value *SafeOp2 = getSafeNoWrapCopy(I->getOperand(2));
+      // Build the swapped select to represent the negation. Preserve metadata.
+      return Builder.CreateSelect(I->getOperand(0), SafeOp2, SafeOp1,
+                                  I->getName() + ".neg", /*MDFrom=*/I);
     }
     // `select` is negatible if both hands of `select` are negatible.
     Value *NegOp1 = negate(I->getOperand(1), IsNSW, Depth + 1);

reason_thou:
1. Understanding the Issue:
The transformation turns:
  %t0 = sub nsw i8 0, %x
  %t1 = select i1 %c, i8 %x, i8 %t0
  %t2 = sub i8 %y, %t1
into:
  %1  = select i1 %c, i8 %t0, i8 %x
  %t2 = add i8 %1, %y
This introduces poison: if %x == INT_MIN and %c == true, the source select chooses %x (non-poison) while the target select chooses %t0 (poison due to nsw overflow). Alive2 confirms target is more poisonous than source.

2. Analyzing opt's Log:
The first (and only) transformation comes from InstCombine Negator:
- Negator sinks the negation of the select by swapping select arms because it recognized the arms as negations of each other, and then rewrites sub into add.
The log shows “successfully sunk negation into select” and the swapped select is created. There is no other analysis involved (no AA pointers). The error arises from this swap.

3. Root Cause Analysis:
There are two related issues in Negator:
- In visitImpl(), the special-case for select swaps arms if isKnownNegation(Op1, Op2) holds. That predicate returns true for pairs like (X, sub 0, X) regardless of overflow flags (NSW/NUW). Swapping is only semantics-preserving for representing "-select(c,A,B)" as "select(c,-A, -B)" if choosing the swapped arm does not introduce poison compared to computing -select. If the negated arm is sub nsw 0, X, selecting it can produce poison that would not be produced by computing -select (which would not use that arm when c selects the other arm). This is exactly the failing case.
- Independently, there is a general pattern “-(-(X)) -> X” implemented as: if (match(V, m_Neg(m_Value(X)))) return X;. This ignores overflow flags. If V is "sub nsw 0, X", then -(V) is poison when X = INT_MIN, but returning X is not. So the pattern is invalid with poison-generating flags.

Therefore, the Negator incorrectly ignores poison semantics (NSW/NUW) when: (a) swapping select arms on known-negation arms, and (b) simplifying double negation.

4. Proposed Edit Point(s)
- File: llvm/lib/Transforms/InstCombine/InstCombineNegator.cpp

Edit point 1 (lines 133–141): Guard “-(-(X)) -> X” against nowrap flags. Only fold when the inner negate cannot produce poison (no NSW/NUW):

Replace:
  // -(-(X)) -> X.
  if (match(V, m_Neg(m_Value(X))))
    return X;

With:
  // -(-(X)) -> X, but only if the inner negation cannot produce poison
  // (i.e. it must not have NSW/NUW). Otherwise, -(poison) would be poison,
  // and replacing it with X would be wrong.
  if (auto *InnerBO = dyn_cast<BinaryOperator>(V)) {
    if (InnerBO->getOpcode() == Instruction::Sub &&
        match(InnerBO->getOperand(0), m_ZeroInt()) &&
        match(InnerBO->getOperand(1), m_Value(X))) {
      auto *OBO = cast<OverflowingBinaryOperator>(InnerBO);
      if (!OBO->hasNoSignedWrap() && !OBO->hasNoUnsignedWrap())
        return X;
    }
  }

Edit point 2 (lines 326–338): Make the select-arm swap only happen if both arms have no NSW/NUW (so selecting either arm cannot introduce poison unexpectedly):

Replace the block:
  if (isKnownNegation(I->getOperand(1), I->getOperand(2), /*NeedNSW=*/false,
                      /*AllowPoison=*/false)) {
    // Of one hand of select is known to be negation of another hand,
    // just swap the hands around.
    auto *NewSelect = cast<SelectInst>(I->clone());
    // Just swap the operands of the select.
    NewSelect->swapValues();
    // Don't swap prof metadata, we didn't change the branch behavior.
    NewSelect->setName(I->getName() + ".neg");
    Builder.Insert(NewSelect);
    return NewSelect;
  }

With:
  if (isKnownNegation(I->getOperand(1), I->getOperand(2), /*NeedNSW=*/false,
                      /*AllowPoison=*/false)) {
    // Swapping arms is only safe for representing negation if neither arm
    // can produce poison on selection due to nowrap flags. Otherwise, we may
    // expose poison on a path where -select would not use that arm.
    auto HasNoWrap = [](const Value *V) {
      if (const auto *OBO = dyn_cast<OverflowingBinaryOperator>(V))
        return OBO->hasNoSignedWrap() || OBO->hasNoUnsignedWrap();
      return false;
    };
    if (!HasNoWrap(I->getOperand(1)) && !HasNoWrap(I->getOperand(2))) {
      auto *NewSelect = cast<SelectInst>(I->clone());
      NewSelect->swapValues();
      NewSelect->setName(I->getName() + ".neg");
      Builder.Insert(NewSelect);
      return NewSelect;
    }
    // Otherwise, fall through and try general recursive negation of both arms.
  }

These changes ensure we do not perform unsafe transformations in presence of NSW/NUW flags that can produce poison.

5. Conclusion:
The bug stems from Negator ignoring poison semantics when simplifying negations: swapping select arms on negated pairs and eliminating double negation without checking nowrap flags. The fix gates both transformations on the absence of NSW/NUW flags so we do not introduce additional poison. This prevents the incorrect transform in the reproducer, restoring correctness while preserving the intended optimizations when safe.

